1	import { quote, claim } from "./claim-office.js";
2	
3	const KNOWN_ITEM_TYPES = new Set([
4	  "sword",
5	  "amulet",
6	  "staff",
7	  "potion",
8	  "rune",
9	  "moonstone",
10	]);
11	
12	function assertKnownItemTypes(items: { type: string }[]): void {
13	  for (const item of items) {
14	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
15	      throw new Error(`Unknown item type: ${item.type}`);
16	    }
17	  }
18	}
19	
20	function countByType(types: string[]): Map<string, number> {
21	  const counts = new Map<string, number>();
22	  for (const type of types) {
23	    counts.set(type, (counts.get(type) ?? 0) + 1);
24	  }
25	  return counts;
26	}
27	
28	function assertDamagesValid(
29	  policyItems: { type: string }[],
30	  damages: { itemType: string; amount: number }[],
31	): void {
32	  const coverageCounts = countByType(policyItems.map((item) => item.type));
33	  for (const damage of damages) {
34	    if (!coverageCounts.has(damage.itemType)) {
35	      throw new Error(
36	        `Claim damages an item not in policy: ${damage.itemType}`,
37	      );
38	    }
39	    if (damage.amount < 0) {
40	      throw new Error(`Negative damage amount: ${damage.amount}`);
41	    }
42	  }
43	  const damageCounts = countByType(damages.map((damage) => damage.itemType));
44	  for (const [itemType, count] of damageCounts) {
45	    if (count > (coverageCounts.get(itemType) ?? 0)) {
46	      throw new Error(`Too many damages for item type: ${itemType}`);
47	    }
48	  }
49	}
50	
51	export function runScenario(scenario: any): { results: unknown[] } {
52	  const results: unknown[] = [];
53	  let quoteCount = 0;
54	  const remainingCaps = new Map<number, number>();
55	  for (const step of scenario.steps) {
56	    if (step.op === "quote") {
57	      assertKnownItemTypes(step.items);
58	      const premium = quote({
59	        customer: {
60	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
61	          previousContracts: quoteCount,
62	        },
63	        items: step.items,
64	      });
65	      results.push({ premium });
66	      quoteCount++;
67	    } else if (step.op === "claim") {
68	      const policyStep = scenario.steps[step.policy];
69	      assertDamagesValid(policyStep.items, step.incident.damages);
70	      const { payout, remainingCap = 0 } = claim({
71	        items: policyStep.items,
72	        incident: step.incident,
73	        remainingCap: remainingCaps.get(step.policy),
74	      });
75	      remainingCaps.set(step.policy, remainingCap);
76	      results.push({ payout, remainingCap });
77	    }
78	  }
79	  return { results };
80	}
